$(function() {

    // Cek perubahan data pada setiap form
    let $akunForm = $("#akun-form");
    let formCekAkun = FormHelper.cekFormData($akunForm);
    let $infoForm = $("#info-form");
    let formCekInfo = FormHelper.cekFormData($infoForm);
    
    // Form Update Akun
    $akunForm.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                name: { required: true, minlength: 3, maxlength: 30 },
                email: { required: true, email: true, customEmail: true },
                password: { minlength: 8 },
                password_confirmation: {
                    equalTo: "#akun-form input[name='password']",
                },
            },
            submitHandler: (form) => {
                $akunForm.find(":input").removeClass("is-invalid is-valid");

                if (formCekAkun.isChanged()) {
                    FormHelper.submitForm(
                        form,
                        $(form).attr("action"),
                        $(form).find("button[type=submit]"),
                        $(form).find("#akun-loading"),
                        { formCek: formCekAkun }
                    );
                }
            },
        })
    );

    // Form Update Info
    $infoForm.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                perusahaan: { minlength: 3, maxlength: 30 },
                whatsapp: { number: true, minlength: 8, maxlength: 15 },
                telegram: { number: true, minlength: 8, maxlength: 15 },
                alamat: { minlength: 5, maxlength: 100 },
            },
            submitHandler: (form) => {
                $infoForm.find(":input").removeClass("is-invalid is-valid");

                if (formCekInfo.isChanged()) {
                    FormHelper.submitForm(
                        form,
                        $(form).attr("action"),
                        $(form).find("button[type=submit]"),
                        $(form).find("#info-loading"),
                        { formCek: formCekInfo }
                    );
                }
            },
        })
    );
});

